# ============================================================
# GF(16) INTEGER/NIBBLE CONVERSION
#
# Integer c in F(c) is interpreted in polynomial-basis bits:
#
#   c = b0 + 2*b1 + 4*b2 + 8*b3
#     -> b0 + b1*a + b2*a^2 + b3*a^3
# ============================================================

def int_to_gf16(c):
    c = int(c) & _sage_const_0xF 
    value = F(_sage_const_0 )
    for bit in range(_sage_const_4 ):
        if (c >> bit) & _sage_const_1 :
            value += a**bit
    return value


def gf16_to_int(c):
    c = F(c)
    poly = c.polynomial()
    value = _sage_const_0 
    for bit in range(_sage_const_4 ):
        if bit <= poly.degree() and int(poly[bit]) & _sage_const_1 :
            value |= (_sage_const_1  << bit)
    return value & _sage_const_0xF 


# Sanity-check the nibble mapping.
