# ============================================================
# GF(2^4) POLYNOMIAL SYSTEM -> BOOLEAN POLYNOMIAL SYSTEM
#
# This is the same general conversion style as the SECOND code:
#
#   each GF(16) variable x becomes four Boolean variables
#
#       x_0, x_1, x_2, x_3
#
#   representing
#
#       x = x_0 + x_1*a + x_2*a^2 + x_3*a^3.
#
# GF(16) multiplication is expanded as polynomial multiplication
# over GF(2), followed by reduction modulo a^4 + a + 1.
#
# Unlike the old first code, this does NOT use precomputed
# multiplication matrices. It bit-blasts the Sage GF(16)
# polynomial system directly.
# ============================================================

def gf2m_system_to_gf2(system):
    """
    Convert a polynomial system over GF(2^m) into a Boolean
    polynomial system over GF(2).

    For GF(16), each field variable:

        x

    is represented as:

        x = x_b0
          + x_b1*a
          + x_b2*a^2
          + x_b3*a^3

    using the polynomial basis defined by:

        a^4 + a + 1 = 0

    Each GF(16) equation produces exactly 4 Boolean equations.
    """

    if not system:
        raise ValueError(
            "GF(16) system is empty"
        )

    # ========================================================
    # Original polynomial ring over GF(16)
    # ========================================================

    R_ext = system[_sage_const_0 ].parent()

    F_ext = R_ext.base_ring()

    m = F_ext.degree()

    vars_ext = list(
        R_ext.gens()
    )

    n = len(vars_ext)

    print("\n========================================")
    print("GF(16) -> GF(2) CONVERSION")
    print("========================================")

    print(
        "Extension degree m :",
        m
    )

    print(
        "GF(16) variables   :",
        n
    )

    print(
        "GF(16) equations   :",
        len(system)
    )

    # ========================================================
    # Modulus
    #
    # For MAYO:
    #
    #     a^4 + a + 1
    #
    # ========================================================

    modulus = F_ext.modulus()

    modulus_coeffs = list(
        modulus.list()
    )

    print(
        "GF(16) modulus     :",
        modulus
    )

    # ========================================================
    # Boolean ring
    #
    # Each GF(16) variable gets m Boolean variables.
    # ========================================================

    bool_names = []

    for var in vars_ext:

        for bit in range(m):

            bool_names.append(
                "%s_b%d"
                %
                (
                    str(var),
                    bit
                )
            )

    B = BooleanPolynomialRing(
        n * m,
        names=bool_names
    )

    Bvars = list(
        B.gens()
    )

    # ========================================================
    # Map:
    #
    # GF(16):
    #
    #     x_0_0
    #
    # ->
    #
    # GF(2):
    #
    #     [
    #       x_0_0_b0,
    #       x_0_0_b1,
    #       x_0_0_b2,
    #       x_0_0_b3
    #     ]
    #
    # ========================================================

    var_bits = {}

    index = _sage_const_0 

    for var in vars_ext:

        var_bits[var] = list(
            Bvars[
                index:
                index + m
            ]
        )

        index += m

    # ========================================================
    # Convert GF(16) element -> bit vector
    #
    # Example:
    #
    #     a^3 + a + 1
    #
    # ->
    #
    #     [1,1,0,1]
    #
    # ========================================================

    def field_element_to_bits(c):

        c = F_ext(c)

        poly = c.polynomial()

        coeffs = list(
            poly.list()
        )

        coeffs += [
            _sage_const_0 
        ] * (
            m - len(coeffs)
        )

        return [

            B(
                int(coeffs[i])
            )

            for i in range(m)

        ]

    # ========================================================
    # GF(16) symbolic multiplication
    #
    # Inputs:
    #
    #     u = [u0,u1,u2,u3]
    #     v = [v0,v1,v2,v3]
    #
    # representing:
    #
    #     u0 + u1*a + ...
    #
    # Multiply polynomially, then reduce modulo:
    #
    #     a^4 + a + 1
    #
    # ========================================================

    def field_mult(u_bits, v_bits):

        tmp = [

            B(_sage_const_0 )

            for _ in range(
                _sage_const_2  * m - _sage_const_1 
            )

        ]

        # ----------------------------------------------------
        # Polynomial multiplication
        # ----------------------------------------------------

        for i in range(m):

            for j in range(m):

                tmp[i + j] += (
                    u_bits[i]
                    *
                    v_bits[j]
                )

        # ----------------------------------------------------
        # Modular reduction
        #
        # modulus:
        #
        #     a^m + p_(m-1)a^(m-1) + ... + p0
        #
        # Since characteristic = 2:
        #
        #     a^m =
        #       p_(m-1)a^(m-1) + ... + p0
        #
        # ----------------------------------------------------

        for degree in range(
            _sage_const_2  * m - _sage_const_2 ,
            m - _sage_const_1 ,
            -_sage_const_1 
        ):

            high = tmp[
                degree
            ]

            if high == B(_sage_const_0 ):

                continue

            for i in range(m):

                if (
                    int(
                        modulus_coeffs[i]
                    )
                    & _sage_const_1 
                ):

                    tmp[
                        degree - m + i
                    ] += high

            tmp[
                degree
            ] = B(_sage_const_0 )

        return tmp[:m]

    # ========================================================
    # Multiply bit vector by GF variable^exponent
    # ========================================================

    def multiply_by_variable_power(
        term_bits,
        variable,
        exponent
    ):

        result = list(
            term_bits
        )

        bits = var_bits[
            variable
        ]

        for _ in range(
            exponent
        ):

            result = field_mult(
                result,
                bits
            )

        return result

    # ========================================================
    # MAIN CONVERSION
    # ========================================================

    boolean_eqs = []

    print(
        "\nConverting equations..."
    )

    for eq_index, f in enumerate(
        system
    ):

        # Resulting GF(16) value:
        #
        #     result[0]
        #       + result[1]*a
        #       + result[2]*a^2
        #       + result[3]*a^3

        result = [

            B(_sage_const_0 )

            for _ in range(m)

        ]

        # ====================================================
        # IMPORTANT FIX
        #
        # Explicitly iterate over Sage monomials instead of
        # relying on f.dict().
        # ====================================================

        monomials = f.monomials()

        for mon in monomials:

            # ------------------------------------------------
            # Get coefficient of this monomial
            # ------------------------------------------------

            coeff = F_ext(
                f.monomial_coefficient(
                    mon
                )
            )

            # Start term with coefficient bits
            term_bits = field_element_to_bits(
                coeff
            )

            # ------------------------------------------------
            # Extract exponent tuple
            #
            # Example:
            #
            #     x0*x3^2
            #
            # ->
            #
            #     (1,0,0,2,...)
            #
            # ------------------------------------------------

            exponent_tuple = tuple(
                mon.exponents()[_sage_const_0 ]
            )

            if len(
                exponent_tuple
            ) != n:

                raise RuntimeError(
                    "Exponent tuple length mismatch: "
                    "%d != %d"
                    %
                    (
                        len(
                            exponent_tuple
                        ),
                        n
                    )
                )

            # ------------------------------------------------
            # Multiply coefficient by every variable power
            # ------------------------------------------------

            for var_index, exponent in enumerate(
                exponent_tuple
            ):

                exponent = int(
                    exponent
                )

                if exponent == _sage_const_0 :

                    continue

                variable = vars_ext[
                    var_index
                ]

                term_bits = (
                    multiply_by_variable_power(
                        term_bits,
                        variable,
                        exponent
                    )
                )

            # ------------------------------------------------
            # Add term into equation
            #
            # GF(16) addition = component-wise XOR
            # ------------------------------------------------

            for bit in range(m):

                result[
                    bit
                ] += term_bits[
                    bit
                ]

        # ----------------------------------------------------
        # Each GF(16) equation gives m Boolean equations.
        # ----------------------------------------------------

        for bit in range(m):

            boolean_eqs.append(
                B(
                    result[
                        bit
                    ]
                )
            )

        

    # ========================================================
    # FINAL SANITY CHECK
    # ========================================================

    print("\n========================================")
    print("GF(16) -> GF(2) CONVERSION SUMMARY")
    print("========================================")

    print(
        "GF(16) equations :",
        len(system)
    )

    print(
        "Expected Boolean :",
        len(system) * m
    )

    print(
        "Actual Boolean   :",
        len(boolean_eqs)
    )

    nonzero = sum(

        _sage_const_1 

        for f in boolean_eqs

        if f != B(_sage_const_0 )

    )

    print(
        "Nonzero Boolean  :",
        nonzero
    )

    print(
        "Zero Boolean     :",
        len(boolean_eqs)
        -
        nonzero
    )

    if len(boolean_eqs) != (
        len(system) * m
    ):

        raise RuntimeError(
            "Incorrect number of Boolean equations"
        )

    if nonzero == _sage_const_0 :

        raise RuntimeError(
            "ALL Boolean equations became zero. "
            "GF(16) -> GF(2) conversion failed."
        )

    return (
        B,
        var_bits,
        boolean_eqs
    )


